<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { ElMessage } from 'element-plus'
import { adminApi, type SeckillActivity, type SeckillConsistency } from '@/api/services'
const rows=ref<SeckillActivity[]>([]);const loading=ref(false);const dialog=ref(false);const saving=ref(false);const consistency=ref<SeckillConsistency>();const consistencyVisible=ref(false)
const form=reactive({name:'',skuId:undefined as number|undefined,seckillPrice:0,totalStock:1,time:[] as Date[]})
const load=async()=>{loading.value=true;try{rows.value=await adminApi.seckillActivities()}finally{loading.value=false}}
const iso=(d:Date)=>{const pad=(n:number)=>String(n).padStart(2,'0');return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`}
const create=async()=>{if(!form.skuId||form.time.length!==2)return ElMessage.warning('请完整填写活动信息');saving.value=true;try{await adminApi.createSeckill({name:form.name,skuId:form.skuId,seckillPrice:form.seckillPrice,totalStock:form.totalStock,startTime:iso(form.time[0]),endTime:iso(form.time[1])});ElMessage.success('活动已创建');dialog.value=false;load()}finally{saving.value=false}}
const action=async(kind:'activate'|'warmup'|'end',id:number)=>{if(kind==='activate')await adminApi.activateSeckill(id);else if(kind==='warmup')await adminApi.warmupSeckill(id);else await adminApi.endSeckill(id);ElMessage.success(kind==='activate'?'已激活并预热':kind==='warmup'?'Redis 库存已重建':'活动已结束');load()}
const inspect=async(id:number)=>{consistency.value=await adminApi.seckillConsistency(id);consistencyVisible.value=true}
const time=(v:string)=>v?.replace('T',' ').slice(0,19)
onMounted(load)
</script>
<template><div><div class="admin-page-title"><div><span>HIGH CONCURRENCY LAB</span><h1>秒杀控制台</h1><p>Redis 原子预扣 → RocketMQ 排队 → MySQL 异步落库，并实时核对三方库存。</p></div><el-button type="primary" @click="dialog=true">创建活动</el-button></div><section class="admin-card"><el-alert title="一致性口径：Redis 剩余库存 = 数据库活动库存 = 初始库存 - 成功落库单数；消息积压期间允许短暂不一致。" type="info" show-icon :closable="false"/><el-table v-loading="loading" :data="rows" style="margin-top:18px"><el-table-column prop="id" label="ID" width="70"/><el-table-column prop="name" label="活动" min-width="160"/><el-table-column prop="skuId" label="SKU" width="90"/><el-table-column label="价格" width="100"><template #default="s">¥{{Number(s.row.seckillPrice).toFixed(2)}}</template></el-table-column><el-table-column label="DB 库存" width="110"><template #default="s">{{s.row.availableStock}} / {{s.row.totalStock}}</template></el-table-column><el-table-column label="活动时间" min-width="300"><template #default="s">{{time(s.row.startTime)}} — {{time(s.row.endTime)}}</template></el-table-column><el-table-column prop="status" label="状态" width="100"/><el-table-column label="操作" width="280" fixed="right"><template #default="s"><el-button v-if="s.row.status==='DRAFT'" link type="success" @click="action('activate',s.row.id)">激活+预热</el-button><el-button v-if="s.row.status==='ACTIVE'" link @click="action('warmup',s.row.id)">重建缓存</el-button><el-button v-if="s.row.status==='ACTIVE'" link type="danger" @click="action('end',s.row.id)">结束</el-button><el-button link type="primary" @click="inspect(s.row.id)">一致性检查</el-button></template></el-table-column></el-table></section><el-dialog v-model="dialog" title="创建秒杀活动" width="600px"><el-form :model="form" label-width="90px"><el-form-item label="活动名称" required><el-input v-model="form.name"/></el-form-item><el-form-item label="SKU ID" required><el-input-number v-model="form.skuId" :min="1"/></el-form-item><el-form-item label="秒杀价格" required><el-input-number v-model="form.seckillPrice" :min="0.01" :precision="2"/></el-form-item><el-form-item label="活动库存" required><el-input-number v-model="form.totalStock" :min="1"/></el-form-item><el-form-item label="活动时间" required><el-date-picker v-model="form.time" type="datetimerange" start-placeholder="开始" end-placeholder="结束"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" :loading="saving" @click="create">创建</el-button></template></el-dialog><el-dialog v-model="consistencyVisible" title="库存一致性检查" width="620px"><el-result v-if="consistency" :icon="consistency.consistent?'success':'warning'" :title="consistency.consistent?'库存已收敛':'消息处理中或存在差异'" :sub-title="`活动 #${consistency.activityId}`"><template #extra><el-descriptions :column="2" border><el-descriptions-item label="初始库存">{{consistency.initialStock}}</el-descriptions-item><el-descriptions-item label="Redis 库存">{{consistency.redisStock}}</el-descriptions-item><el-descriptions-item label="数据库库存">{{consistency.databaseStock}}</el-descriptions-item><el-descriptions-item label="成功订单">{{consistency.successfulOrders}}</el-descriptions-item><el-descriptions-item label="估算积压" :span="2">{{consistency.pendingMessages}}</el-descriptions-item></el-descriptions></template></el-result></el-dialog></div></template>
